data=[]
for line in open('data/mao.trn'):
    l,f,ft=line.rstrip('\n').split('\t')
    data.append((l,f,ft))
from collections import Counter,defaultdict
pf=defaultdict(set)
for l,f,ft in data:
    if ft=='V;PASS': pf[l].add(f)
items=[(l,sorted(v)[0]) for l,v in pf.items()]

def suffix_of(l,f): return f[len(l):] if f.startswith(l) else '!'+f

def make_predict(train, mode):
    b2=defaultdict(Counter); b1=defaultdict(Counter); g=Counter()
    for l,f in train:
        s=suffix_of(l,f); b2[l[-2:]][s]+=1; b1[l[-1]][s]+=1; g[s]+=1
    gdef=g.most_common(1)[0][0]
    def pred(l):
        seq = [(b2,l[-2:]),(b1,l[-1])] if mode=='b2' else [(b1,l[-1])]
        for tbl,key in seq:
            if tbl[key]: 
                s=tbl[key].most_common(1)[0][0]; break
        else:
            s=gdef
        return s[1:] if s.startswith('!') else l+s
    return pred

for mode in ['b1','b2']:
    correct=0
    for i,(l,f) in enumerate(items):
        train=[items[j] for j in range(len(items)) if j!=i]
        p=make_predict(train,mode)
        if p(l)==f: correct+=1
    print(mode, f"{correct}/{len(items)} = {correct/len(items):.3f}")

# constant baselines
for const in ['a','tia','ia','hia']:
    c=sum(1 for l,f in items if f==l+const)
    print(f"const -{const}: {c}/{len(items)} = {c/len(items):.3f}")
